import React, { useEffect } from 'react';
import { Container } from 'react-bootstrap';
import './CustomParallax.css';

const CustomParallax = ({ layers, scrollPercentage }) => {
  useEffect(() => {
    layers.forEach((layer, index) => {
      const mount = document.querySelector(`#layer${index}`);
      if (mount) {
        const speed = layer.speed;
        const initialOffset = parseFloat(layer.initialOffset.replace('px', ''));
        const transformValue = (scrollPercentage * speed) + initialOffset;
        mount.style.transform = `translateX(${transformValue}px)`;
      }
    });
  }, [layers, scrollPercentage]);

  return (
    <div className="section_parallax">
      <Container>
        {layers.map((layer, index) => (
          <img
            key={index}
            id={`layer${index}`}
            src={layer.image}
            alt={`Layer ${index}`}
            className="parallax-layer"
            style={{ zIndex: layers.length - index }}
          />
        ))}
      </Container>
    </div>
  );
};

export default CustomParallax;
